def markdown_table_to_json(params: dict) -> str:
    """Convert a markdown table string to a JSON array of objects."""
    import json
    import re

    table_text = params.get("table", "")
    if not table_text:
        return json.dumps([])

    lines = [line.strip() for line in table_text.split("\n") if line.strip()]
    if len(lines) < 2:
        return json.dumps([])

    # Extract header row
    headers = [h.strip() for h in lines[0].split("|") if h.strip()]
    if not headers:
        return json.dumps([])

    # Skip separator row (e.g., |---|---|)
    data_lines = []
    for line in lines[1:]:
        if re.match(r"^[\s\|:\-]+$", line):
            continue
        data_lines.append(line)

    result = []
    for line in data_lines:
        cells = [c.strip() for c in line.split("|") if c.strip()]
        if len(cells) != len(headers):
            continue
        row = {}
        for i, header in enumerate(headers):
            row[header] = cells[i]
        result.append(row)

    return json.dumps(result, indent=2)
